     1→/**
     2→ * IndexedDB Service - Unlimited Local Storage
     3→ *
     4→ * Provides a localStorage-like interface with IndexedDB backend
     5→ * Benefits:
     6→ * - 50GB+ storage capacity (vs 5-10MB localStorage)
     7→ * - Handles large data (images, rich text, etc.)
     8→ * - Async operations for better performance
     9→ * - Automatic versioning and migrations
    10→ */
    11→
    12→import { logger } from './logger';
    13→
    14→const log = logger.module('IndexedDB');
    15→
    16→const DB_NAME = 'neuman-brain-db';
    17→const DB_VERSION = 1;
    18→const STORE_NAME = 'brain-data';
    19→
    20→interface DBConnection {
    21→  db: IDBDatabase | null;
    22→  isReady: boolean;
    23→}
    24→
    25→class IndexedDBService {
    26→  private connection: DBConnection = {
    27→    db: null,
    28→    isReady: false,
    29→  };
    30→
    31→  /**
    32→   * Initialize IndexedDB connection
    33→   */
    34→  async init(): Promise<void> {
    35→    if (this.connection.isReady) {
    36→      return;
    37→    }
    38→
    39→    return new Promise((resolve, reject) => {
    40→      const request = indexedDB.open(DB_NAME, DB_VERSION);
    41→
    42→      request.onerror = () => {
    43→        log.error('Failed to open IndexedDB', { error: request.error });
    44→        reject(request.error);
    45→      };
    46→
    47→      request.onsuccess = () => {
    48→        this.connection.db = request.result;
    49→        this.connection.isReady = true;
    50→        log.info('IndexedDB initialized');
    51→        resolve();
    52→      };
    53→
    54→      request.onupgradeneeded = (event) => {
    55→        const db = (event.target as IDBOpenDBRequest).result;
    56→
    57→        // Create object store if it doesn't exist
    58→        if (!db.objectStoreNames.contains(STORE_NAME)) {
    59→          db.createObjectStore(STORE_NAME);
    60→          log.info('Created IndexedDB object store');
    61→        }
    62→      };
    63→    });
    64→  }
    65→
    66→  /**
    67→   * Get item from IndexedDB
    68→   */
    69→  async getItem(key: string): Promise<string | null> {
    70→    await this.init();
    71→
    72→    return new Promise((resolve, reject) => {
    73→      if (!this.connection.db) {
    74→        reject(new Error('IndexedDB not initialized'));
    75→        return;
    76→      }
    77→
    78→      const transaction = this.connection.db.transaction(STORE_NAME, 'readonly');
    79→      const store = transaction.objectStore(STORE_NAME);
    80→      const request = store.get(key);
    81→
    82→      request.onsuccess = () => {
    83→        resolve(request.result ?? null);
    84→      };
    85→
    86→      request.onerror = () => {
    87→        log.error('Failed to get from IndexedDB', { key, error: request.error });
    88→        reject(request.error);
    89→      };
    90→    });
    91→  }
    92→
    93→  /**
    94→   * Set item in IndexedDB
    95→   */
    96→  async setItem(key: string, value: string): Promise<void> {
    97→    await this.init();
    98→
    99→    return new Promise((resolve, reject) => {
   100→      if (!this.connection.db) {
   101→        reject(new Error('IndexedDB not initialized'));
   102→        return;
   103→      }
   104→
   105→      const transaction = this.connection.db.transaction(STORE_NAME, 'readwrite');
   106→      const store = transaction.objectStore(STORE_NAME);
   107→      const request = store.put(value, key);
   108→
   109→      request.onsuccess = () => {
   110→        resolve();
   111→      };
   112→
   113→      request.onerror = () => {
   114→        log.error('Failed to set in IndexedDB', { key, error: request.error });
   115→        reject(request.error);
   116→      };
   117→    });
   118→  }
   119→
   120→  /**
   121→   * Remove item from IndexedDB
   122→   */
   123→  async removeItem(key: string): Promise<void> {
   124→    await this.init();
   125→
   126→    return new Promise((resolve, reject) => {
   127→      if (!this.connection.db) {
   128→        reject(new Error('IndexedDB not initialized'));
   129→        return;
   130→      }
   131→
   132→      const transaction = this.connection.db.transaction(STORE_NAME, 'readwrite');
   133→      const store = transaction.objectStore(STORE_NAME);
   134→      const request = store.delete(key);
   135→
   136→      request.onsuccess = () => {
   137→        resolve();
   138→      };
   139→
   140→      request.onerror = () => {
   141→        log.error('Failed to remove from IndexedDB', { key, error: request.error });
   142→        reject(request.error);
   143→      };
   144→    });
   145→  }
   146→
   147→  /**
   148→   * Get all keys from IndexedDB
   149→   */
   150→  async getAllKeys(): Promise<string[]> {
   151→    await this.init();
   152→
   153→    return new Promise((resolve, reject) => {
   154→      if (!this.connection.db) {
   155→        reject(new Error('IndexedDB not initialized'));
   156→        return;
   157→      }
   158→
   159→      const transaction = this.connection.db.transaction(STORE_NAME, 'readonly');
   160→      const store = transaction.objectStore(STORE_NAME);
   161→      const request = store.getAllKeys();
   162→
   163→      request.onsuccess = () => {
   164→        resolve(request.result as string[]);
   165→      };
   166→
   167→      request.onerror = () => {
   168→        log.error('Failed to get all keys from IndexedDB', { error: request.error });
   169→        reject(request.error);
   170→      };
   171→    });
   172→  }
   173→
   174→  /**
