export const Layout: React.FC<LayoutProps> = ({ children }) => {
  const { isCollapsed, toggleMobileMenu } = useSidebarStore();
  const { isOpen: isTerminalOpen, toggleTerminal } = useTerminalStore();
  const [showSupportModal, setShowSupportModal] = useState(false);

  // Global keyboard shortcut: F1 or Cmd+Ctrl+/ to open help
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // F1 key
      if (e.key === 'F1') {
        e.preventDefault();
        setShowSupportModal(true);
        return;
      }

      // Cmd+Ctrl+/ (Mac) or Ctrl+/ (Windows/Linux)
      if (e.key === '/' && (e.metaKey || e.ctrlKey)) {
        e.preventDefault();
        setShowSupportModal(true);
        return;
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

      {/* Error Toast Notifications */}
      <ErrorToastContainer />

      {/* Global Support Modal (F1 or Cmd+Ctrl+/) */}
      <SupportModal isOpen={showSupportModal} onClose={() => setShowSupportModal(false)} />
    </div>
  );
};

